import{_ as e,o as r,c as l,ai as i}from"./chunks/framework.ampVZV4B.js";const g=JSON.parse('{"title":"Node.js 开源项目","description":"","frontmatter":{},"headers":[],"relativePath":"open-source/nodejs-projects.md","filePath":"open-source/nodejs-projects.md"}'),a={name:"open-source/nodejs-projects.md"};function o(s,t,h,n,u,p){return r(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="node-js-开源项目" tabindex="-1">Node.js 开源项目 <a class="header-anchor" href="#node-js-开源项目" aria-label="Permalink to “Node.js 开源项目”">​</a></h1><p>本页面精选了优秀的Node.js开源项目，包括Web框架、工具库、应用系统等。</p><h2 id="web-框架" tabindex="-1">Web 框架 <a class="header-anchor" href="#web-框架" aria-label="Permalink to “Web 框架”">​</a></h2><h3 id="全栈框架" tabindex="-1">全栈框架 <a class="header-anchor" href="#全栈框架" aria-label="Permalink to “全栈框架”">​</a></h3><ul><li><p><strong>Express.js</strong>：经典Web框架</p><ul><li>GitHub: <a href="https://github.com/expressjs/express" target="_blank" rel="noreferrer">https://github.com/expressjs/express</a></li><li>特点: 轻量级、灵活、中间件机制</li><li>适用: RESTful API、Web应用</li></ul></li><li><p><strong>NestJS</strong>：企业级Node.js框架</p><ul><li>GitHub: <a href="https://github.com/nestjs/nest" target="_blank" rel="noreferrer">https://github.com/nestjs/nest</a></li><li>特点: TypeScript、依赖注入、模块化</li><li>适用: 企业应用、微服务</li></ul></li><li><p><strong>Koa.js</strong>：下一代Web框架</p><ul><li>GitHub: <a href="https://github.com/koajs/koa" target="_blank" rel="noreferrer">https://github.com/koajs/koa</a></li><li>特点: 异步处理、Context对象、轻量级</li><li>适用: 现代Web应用</li></ul></li><li><p><strong>Fastify</strong>：高性能Web框架</p><ul><li>GitHub: <a href="https://github.com/fastify/fastify" target="_blank" rel="noreferrer">https://github.com/fastify/fastify</a></li><li>特点: 快速、JSON Schema验证、低开销</li><li>适用: 高性能API</li></ul></li></ul><h3 id="实时应用框架" tabindex="-1">实时应用框架 <a class="header-anchor" href="#实时应用框架" aria-label="Permalink to “实时应用框架”">​</a></h3><ul><li><p><strong>Socket.IO</strong>：实时双向通信</p><ul><li>GitHub: <a href="https://github.com/socketio/socket.io" target="_blank" rel="noreferrer">https://github.com/socketio/socket.io</a></li><li>功能: WebSocket、实时通信、房间管理</li></ul></li><li><p><strong>Primus</strong>：实时框架抽象层</p><ul><li>GitHub: <a href="https://github.com/primus/primus" target="_blank" rel="noreferrer">https://github.com/primus/primus</a></li><li>功能: 多传输协议、自动降级</li></ul></li></ul><h2 id="工具库" tabindex="-1">工具库 <a class="header-anchor" href="#工具库" aria-label="Permalink to “工具库”">​</a></h2><h3 id="http客户端" tabindex="-1">HTTP客户端 <a class="header-anchor" href="#http客户端" aria-label="Permalink to “HTTP客户端”">​</a></h3><ul><li><p><strong>Axios</strong>：Promise-based HTTP客户端</p><ul><li>GitHub: <a href="https://github.com/axios/axios" target="_blank" rel="noreferrer">https://github.com/axios/axios</a></li><li>功能: HTTP请求、拦截器、自动转换</li></ul></li><li><p><strong>Got</strong>：人性化的HTTP请求库</p><ul><li>GitHub: <a href="https://github.com/sindresorhus/got" target="_blank" rel="noreferrer">https://github.com/sindresorhus/got</a></li><li>功能: 简洁API、自动重试、流式响应</li></ul></li><li><p><strong>Node Fetch</strong>：浏览器Fetch API实现</p><ul><li>GitHub: <a href="https://github.com/node-fetch/node-fetch" target="_blank" rel="noreferrer">https://github.com/node-fetch/node-fetch</a></li><li>功能: 兼容浏览器Fetch API</li></ul></li></ul><h3 id="工具库-1" tabindex="-1">工具库 <a class="header-anchor" href="#工具库-1" aria-label="Permalink to “工具库”">​</a></h3><ul><li><p><strong>Lodash</strong>：实用工具函数库</p><ul><li>GitHub: <a href="https://github.com/lodash/lodash" target="_blank" rel="noreferrer">https://github.com/lodash/lodash</a></li><li>功能: 函数式编程、数据操作</li></ul></li><li><p><strong>Moment.js</strong>：日期处理库</p><ul><li>GitHub: <a href="https://github.com/moment/moment" target="_blank" rel="noreferrer">https://github.com/moment/moment</a></li><li>功能: 日期解析、格式化、操作</li></ul></li><li><p><strong>UUID</strong>：唯一标识符生成</p><ul><li>GitHub: <a href="https://github.com/uuidjs/uuid" target="_blank" rel="noreferrer">https://github.com/uuidjs/uuid</a></li><li>功能: UUID生成、多种版本支持</li></ul></li></ul><h3 id="异步处理" tabindex="-1">异步处理 <a class="header-anchor" href="#异步处理" aria-label="Permalink to “异步处理”">​</a></h3><ul><li><p><strong>Async</strong>：异步流程控制</p><ul><li>GitHub: <a href="https://github.com/caolan/async" target="_blank" rel="noreferrer">https://github.com/caolan/async</a></li><li>功能: 并行/串行执行、流程控制</li></ul></li><li><p><strong>Bluebird</strong>：Promise库</p><ul><li>GitHub: <a href="https://github.com/petkaantonov/bluebird" target="_blank" rel="noreferrer">https://github.com/petkaantonov/bluebird</a></li><li>功能: Promise扩展、性能优化</li></ul></li></ul><h2 id="数据库相关" tabindex="-1">数据库相关 <a class="header-anchor" href="#数据库相关" aria-label="Permalink to “数据库相关”">​</a></h2><h3 id="orm" tabindex="-1">ORM <a class="header-anchor" href="#orm" aria-label="Permalink to “ORM”">​</a></h3><ul><li><p><strong>Sequelize</strong>：多数据库ORM</p><ul><li>GitHub: <a href="https://github.com/sequelize/sequelize" target="_blank" rel="noreferrer">https://github.com/sequelize/sequelize</a></li><li>支持: MySQL、PostgreSQL、SQLite等</li></ul></li><li><p><strong>TypeORM</strong>：TypeScript ORM</p><ul><li>GitHub: <a href="https://github.com/typeorm/typeorm" target="_blank" rel="noreferrer">https://github.com/typeorm/typeorm</a></li><li>特点: TypeScript支持、多数据库</li></ul></li><li><p><strong>Mongoose</strong>：MongoDB ODM</p><ul><li>GitHub: <a href="https://github.com/Automattic/mongoose" target="_blank" rel="noreferrer">https://github.com/Automattic/mongoose</a></li><li>功能: Schema定义、数据验证</li></ul></li></ul><h3 id="数据库客户端" tabindex="-1">数据库客户端 <a class="header-anchor" href="#数据库客户端" aria-label="Permalink to “数据库客户端”">​</a></h3><ul><li><p><strong>mysql2</strong>：MySQL客户端</p><ul><li>GitHub: <a href="https://github.com/sidorares/node-mysql2" target="_blank" rel="noreferrer">https://github.com/sidorares/node-mysql2</a></li><li>特点: 性能高、Promise支持</li></ul></li><li><p><strong>pg</strong>：PostgreSQL客户端</p><ul><li>GitHub: <a href="https://github.com/brianc/node-postgres" target="_blank" rel="noreferrer">https://github.com/brianc/node-postgres</a></li><li>功能: 连接池、查询构建</li></ul></li><li><p><strong>redis</strong>：Redis客户端</p><ul><li>GitHub: <a href="https://github.com/redis/node-redis" target="_blank" rel="noreferrer">https://github.com/redis/node-redis</a></li><li>功能: 集群支持、发布订阅</li></ul></li></ul><h2 id="构建工具" tabindex="-1">构建工具 <a class="header-anchor" href="#构建工具" aria-label="Permalink to “构建工具”">​</a></h2><h3 id="包管理" tabindex="-1">包管理 <a class="header-anchor" href="#包管理" aria-label="Permalink to “包管理”">​</a></h3><ul><li><p><strong>npm</strong>：Node.js包管理器</p><ul><li>GitHub: <a href="https://github.com/npm/cli" target="_blank" rel="noreferrer">https://github.com/npm/cli</a></li><li>功能: 包安装、脚本运行</li></ul></li><li><p><strong>Yarn</strong>：快速包管理器</p><ul><li>GitHub: <a href="https://github.com/yarnpkg/yarn" target="_blank" rel="noreferrer">https://github.com/yarnpkg/yarn</a></li><li>特点: 并行安装、离线缓存</li></ul></li><li><p><strong>pnpm</strong>：高效包管理器</p><ul><li>GitHub: <a href="https://github.com/pnpm/pnpm" target="_blank" rel="noreferrer">https://github.com/pnpm/pnpm</a></li><li>特点: 磁盘空间节省、硬链接</li></ul></li></ul><h3 id="构建工具-1" tabindex="-1">构建工具 <a class="header-anchor" href="#构建工具-1" aria-label="Permalink to “构建工具”">​</a></h3><ul><li><p><strong>Webpack</strong>：模块打包器</p><ul><li>GitHub: <a href="https://github.com/webpack/webpack" target="_blank" rel="noreferrer">https://github.com/webpack/webpack</a></li><li>功能: 代码分割、资源优化</li></ul></li><li><p><strong>Vite</strong>：下一代构建工具</p><ul><li>GitHub: <a href="https://github.com/vitejs/vite" target="_blank" rel="noreferrer">https://github.com/vitejs/vite</a></li><li>特点: 快速冷启动、热重载</li></ul></li><li><p><strong>Parcel</strong>：零配置打包器</p><ul><li>GitHub: <a href="https://github.com/parcel-bundler/parcel" target="_blank" rel="noreferrer">https://github.com/parcel-bundler/parcel</a></li><li>特点: 零配置、开箱即用</li></ul></li></ul><h2 id="测试框架" tabindex="-1">测试框架 <a class="header-anchor" href="#测试框架" aria-label="Permalink to “测试框架”">​</a></h2><ul><li><p><strong>Jest</strong>：愉快的测试框架</p><ul><li>GitHub: <a href="https://github.com/facebook/jest" target="_blank" rel="noreferrer">https://github.com/facebook/jest</a></li><li>功能: 单元测试、快照测试、覆盖率</li></ul></li><li><p><strong>Mocha</strong>：灵活的测试框架</p><ul><li>GitHub: <a href="https://github.com/mochajs/mocha" target="_blank" rel="noreferrer">https://github.com/mochajs/mocha</a></li><li>特点: 插件化、多种报告格式</li></ul></li><li><p><strong>AVA</strong>：并发测试运行器</p><ul><li>GitHub: <a href="https://github.com/avajs/ava" target="_blank" rel="noreferrer">https://github.com/avajs/ava</a></li><li>特点: 并发运行、简洁语法</li></ul></li></ul><h2 id="应用项目" tabindex="-1">应用项目 <a class="header-anchor" href="#应用项目" aria-label="Permalink to “应用项目”">​</a></h2><h3 id="cms系统" tabindex="-1">CMS系统 <a class="header-anchor" href="#cms系统" aria-label="Permalink to “CMS系统”">​</a></h3><ul><li><p><strong>Strapi</strong>：Headless CMS</p><ul><li>GitHub: <a href="https://github.com/strapi/strapi" target="_blank" rel="noreferrer">https://github.com/strapi/strapi</a></li><li>功能: API优先、插件系统</li></ul></li><li><p><strong>Ghost</strong>：专业博客平台</p><ul><li>GitHub: <a href="https://github.com/TryGhost/Ghost" target="_blank" rel="noreferrer">https://github.com/TryGhost/Ghost</a></li><li>功能: Markdown写作、主题系统</li></ul></li><li><p><strong>KeystoneJS</strong>：CMS和Web应用平台</p><ul><li>GitHub: <a href="https://github.com/keystonejs/keystone" target="_blank" rel="noreferrer">https://github.com/keystonejs/keystone</a></li><li>功能: GraphQL API、Admin UI</li></ul></li></ul><h3 id="聊天应用" tabindex="-1">聊天应用 <a class="header-anchor" href="#聊天应用" aria-label="Permalink to “聊天应用”">​</a></h3><ul><li><p><strong>Rocket.Chat</strong>：开源聊天平台</p><ul><li>GitHub: <a href="https://github.com/RocketChat/Rocket.Chat" target="_blank" rel="noreferrer">https://github.com/RocketChat/Rocket.Chat</a></li><li>功能: 实时聊天、文件共享</li></ul></li><li><p><strong>Mattermost</strong>：开源Slack替代品</p><ul><li>GitHub: <a href="https://github.com/mattermost/mattermost" target="_blank" rel="noreferrer">https://github.com/mattermost/mattermost</a></li><li>功能: 团队协作、集成支持</li></ul></li></ul><h3 id="其他应用" tabindex="-1">其他应用 <a class="header-anchor" href="#其他应用" aria-label="Permalink to “其他应用”">​</a></h3><ul><li><p><strong>NodeBB</strong>：现代论坛软件</p><ul><li>GitHub: <a href="https://github.com/NodeBB/NodeBB" target="_blank" rel="noreferrer">https://github.com/NodeBB/NodeBB</a></li><li>功能: 实时讨论、插件丰富</li></ul></li><li><p><strong>Directus</strong>：无头CMS</p><ul><li>GitHub: <a href="https://github.com/directus/directus" target="_blank" rel="noreferrer">https://github.com/directus/directus</a></li><li>功能: REST/GraphQL API、实时更新</li></ul></li></ul>',33)])])}const c=e(a,[["render",o]]);export{g as __pageData,c as default};
